import{_ as t,o,c as a,a2 as i}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"ADR-013 — History API routing","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-013.md","filePath":"adr/ADR-013.md"}'),r={name:"adr/ADR-013.md"};function n(s,e,c,d,l,u){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-013-—-history-api-routing" tabindex="-1">ADR-013 — History API routing <a class="header-anchor" href="#adr-013-—-history-api-routing" aria-label="Permalink to &quot;ADR-013 — History API routing&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-28 Supersedes · ADR-004 (hash routing) TA anchor · §stack · §components/router</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>ADR-004 chose hash routing because it works with any static file server without configuration. SvelteKit&#39;s file-based routing uses the History API by default and produces clean URLs (<code>/explore</code>, <code>/fly</code>, <code>/missions</code>). At production scale, clean URLs matter for sharing, SEO, and basic user trust. The nginx configuration change required is one line.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>History API routing via SvelteKit&#39;s built-in router. Routes are <code>/moon</code>, <code>/explore</code>, <code>/plan</code>, <code>/fly</code>, <code>/missions</code>, <code>/earth</code>. Query params use standard URLSearchParams: <code>/fly?mission=curiosity</code>, <code>/missions?dest=MARS</code>.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>SvelteKit&#39;s router is the right tool — it handles code splitting, prefetching, and navigation transitions out of the box. Clean URLs are table stakes for a production application. The nginx catch-all (<code>try_files $uri /index.html</code>) is a one-line addition that was always going to be needed.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Hash routing</strong> — see ADR-004; works without server config; aesthetically poor; no SEO benefit; rejected for production.</li><li><strong>Hand-written History API router</strong> — RFC-001&#39;s proposed approach; superseded by SvelteKit&#39;s router which is more capable and battle-tested.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: clean URLs; SvelteKit handles code splitting and prefetching automatically; SEO-ready. Negative: requires server-side catch-all redirect (one nginx line); direct URL access requires server config.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p>SvelteKit file-based routing: <code>src/routes/explore/+page.svelte</code>, <code>src/routes/fly/+page.svelte</code>, etc. GitHub Pages requires a <code>404.html</code> redirect workaround for History API — a known pattern, one file.</p>',14)])])}const f=t(r,[["render",n]]);export{p as __pageData,f as default};
